sql:
SELECT AVG(record_count)
FROM (
    SELECT equipment_id, COUNT(*) AS record_count
    FROM maintenance_records
    GROUP BY equipment_id
);

SELECT mr.record_id, mr.maintenance_date, mr.maintenance_result, mr.maintenance_result_num, mr.time_spent, mr.performed_by, e.equipment_id, e.model_id
FROM maintenance_records mr
JOIN equipment e ON mr.equipment_id = e.equipment_id;

SELECT model_id, model_name
FROM equipment_models
WHERE model_id NOT IN (SELECT model_id FROM equipment);

SELECT equipment_id, AVG(calibration_result_num) AS Average_Calibration_Result
FROM calibration_records
GROUP BY equipment_id;

SELECT equipment_models.model_name, equipment_models.model_number, equipment_models.manufacturer
FROM equipment_models
JOIN equipment ON equipment_models.model_id = equipment.model_id;

external_knowledge:
Equipment ID is a unique identifier for each piece of equipment; 
Department may refer to the organizational unit the equipment belongs to; 
Maintenance records may contain information about the maintenance activities performed on the equipment.

sql:
SELECT em.model_name, em.model_description, em.manufacturer, em.model_number, em.equipment_category
FROM equipment_models em
WHERE em.model_id IN (
    SELECT e.model_id FROM equipment e
    WHERE e.status = 'retired'
);
